fun solve(s: String): Long {
    val n = s.length

    // We only need to check indices i up to the midpoint, 
    // because if a match exists at i > n/2, its symmetric counterpart j = n-i-1 
    // is smaller than n/2, and we would have found j earlier.
    // The loop runs while i <= n - 1 - i, which is i <= (n - 1) / 2.
    val limit = (n - 1) / 2

    for (i in 0..limit) {
        val j = n - 1 - i
        if (s[i] == s[j]) {
            // Since we iterate starting from 0, the first match found is the minimum index.
            return i.toLong()
        }
    }

    return -1L
}

